// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ChatConversation) predicate.ChatConversation {
	return predicate.ChatConversation(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ChatConversation) predicate.ChatConversation {
	return predicate.ChatConversation(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ChatConversation) predicate.ChatConversation {
	return predicate.ChatConversation(sql.NotPredicates(p))
}
